@* Single product card — displays image placeholder, name, price, rating, stock badge, add-to-cart *@

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title text-truncate" title="@Product.Name">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2">
            <span class="text-warning">@FilledStars</span><span class="text-muted">@EmptyStars</span>
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-outline-primary mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<Product> OnSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private string FilledStars => new('★', Math.Clamp((int)Math.Round(Product.Rating), 0, 5));
    private string EmptyStars => new('☆', 5 - Math.Clamp((int)Math.Round(Product.Rating), 0, 5));

    private async Task HandleCardClick() => await OnSelected.InvokeAsync(Product);
    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync(Product);
}

@if (Products is null || Products.Count == 0)
{
    <div class="alert alert-info text-center my-4">No products found matching your criteria.</div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired] public List<Product> Products { get; set; } = [];
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">Previous</button>
            </li>
            @foreach (var page in PageNumbers)
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                </li>
            }
            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> PageNumbers
    {
        get
        {
            // Show up to 7 page buttons centered around the current page
            var start = Math.Max(1, CurrentPage - 3);
            var end = Math.Min(TotalPages, start + 6);
            start = Math.Max(1, end - 6);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages || page == CurrentPage) return;
        await OnPageChanged.InvokeAsync(page);
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Left sidebar — filters *@
    <div class="col-md-3 mb-3">
        <CatalogSidebar Categories="categories"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />
    </div>

    @* Main content area *@
    <div class="col-md-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is not null)
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="result.Page"
                            PageSize="result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="currentPage"
                               TotalPages="TotalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    /// <summary>Raised when a product card is clicked so the parent layout can navigate to detail.</summary>
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync(loadCategories: true);
    }

    private async Task LoadDataAsync(bool loadCategories = false)
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            if (loadCategories)
            {
                categories = await ProductService.GetCategoriesAsync();
            }

            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFiltersCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with a cart service
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync(loadCategories: categories is null);
    }
}

